class Solution:
    def minimumRightShifts(self, nums: List[int]) -> int:
        n = len(nums)
        # Find the index where nums[i] > nums[i+1]
        pivot = -1
        for i in range(n - 1):
            if nums[i] > nums[i + 1]:
                pivot = i
                break
        if pivot == -1:
            return 0  # Already sorted
        # Check if the array is rotated sorted
        for i in range(pivot + 1, n - 1):
            if nums[i] > nums[i + 1]:
                return -1
        # Check if the last element is <= first element
        if nums[-1] > nums[0]:
            return -1
        return n - pivot - 1
